// Pseudocode: client-side write with idempotency and topology awareness
client = ManhattanClient(discoveryEndpoint)

function put(key, value) {
  retryCount = 0
  idempotencyToken = generateUUID()
  while (retryCount < 5) {
    partition = client.getPartitionForKey(key)
    node = client.getLeaderForPartition(partition)
    try {
      resp = node.put(key, value, idempotencyToken, timeout=20ms)
      if (resp.success) return true
      if (resp.retryable) {
        sleep(backoff(retryCount))
        retryCount++
        continue
      }
      throw new Error("write failed: " + resp.error)
    } catch (err) {
      // topology might have changed — refresh and retry
      client.refreshTopology()
      retryCount++
      sleep(backoff(retryCount))
    }
  }
  throw new Error("max retries exceeded")
}

